functions.actorsLength:
function actorsLength() external view returns (uint256) {
    return actors.length;
}

functions.deposit:
function deposit(address actorSeed, uint256 amount) external {
    address actor = address(uint160(uint256(keccak256(abi.encodePacked(actorSeed)))));
    if (actor == address(0)) actor = address(0x1);
    uint256 actorTokenBalance = token.balanceOf(actor);
    if (actorTokenBalance == 0) {
        deal(address(token), actor, 1e18);
        actorTokenBalance = 1e18;
    }
    amount = bound(amount, 1, actorTokenBalance > type(uint128).max ? type(uint128).max : actorTokenBalance);
    vm.startPrank(actor);
    token.approve(address(bank), amount);
    bank.deposit(amount);
    vm.stopPrank();
    ghost_total_deposited += amount;
    ghost_balance[actor] += amount;
    if (!_isActor[actor]) {
        _isActor[actor] = true;
        actors.push(actor);
    }
}

functions.withdraw:
function withdraw(address actorSeed, uint256 amount) external {
    address actor = address(uint160(uint256(keccak256(abi.encodePacked(actorSeed)))));
    if (actor == address(0)) actor = address(0x1);
    if (ghost_balance[actor] == 0) return;
    amount = bound(amount, 1, ghost_balance[actor]);
    vm.startPrank(actor);
    bank.withdraw(amount);
    vm.stopPrank();
    ghost_total_withdrawn += amount;
    ghost_withdrawal_count += 1;
    ghost_balance[actor] -= amount;
}

invariants.invariant_individualGhostBalancesMatch:
function invariant_individualGhostBalancesMatch() external view {
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        assertEq(
            bank.balanceOf(actor),
            handler.ghost_balance(actor),
            "bank.balanceOf(actor) != ghost_balance[actor]"
        );
    }
}

invariants.invariant_tokenBalanceEqualsTotalDeposit:
function invariant_tokenBalanceEqualsTotalDeposits() external view {
    assertEq(
        token.balanceOf(address(bank)),
        bank.totalDeposits(),
        "token.balanceOf(bank) != bank.totalDeposits()"
    );
}

invariants.invariant_totalDepositsEqualsGhostNet:
function invariant_totalDepositsEqualsGhostNet() external view {
    uint256 ghostNet = handler.ghost_total_deposited() - handler.ghost_total_withdrawn();
    assertEq(
        bank.totalDeposits(),
        ghostNet,
        "totalDeposits != ghost_total_deposited - ghost_total_withdrawn"
    );
}

invariants.invariant_totalDepositsEqualsSumOfBalanc:
function invariant_totalDepositsEqualsSumOfBalances() external view {
    uint256 sumBalances = 0;
    uint256 len = handler.actorsLength();
    for (uint256 i = 0; i < len; i++) {
        address actor = handler.actors(i);
        sumBalances += bank.balanceOf(actor);
    }
    assertEq(
        bank.totalDeposits(),
        sumBalances,
        "totalDeposits != sum of all actor balances"
    );
}

invariants.invariant_totalDepositsNoUnderflow:
function invariant_totalDepositsNoUnderflow() external view {
    assertLe(
        bank.totalDeposits(),
        handler.ghost_total_deposited(),
        "totalDeposits overflowed above total deposited"
    );
}
